const c = $items("Fetch Case (Plan)")[0]?.json ?? {};
const webhookBody = $node["Webhook - Plan"]?.json?.body ?? {};

const triageData = c.triage_decision ?? {};
const resolutionType =
  triageData.resolution_type ??
  c.resolution_preference ??
  null;

const user_message = {
  case: {
    id: c.id ?? webhookBody.case_id ?? null,
    dispute_type: c.dispute_type ?? null,
    dispute_subtype: c.dispute_subtype ?? null,
    resolution_preference: c.resolution_preference ?? null,
    status: c.status ?? null,
  },
  triage_decision: triageData,
  resolution_type: resolutionType,
  information_bundle: c.information_bundle ?? null,
  affected_items_detail: c.information_bundle?.affected_items_detail ?? [],
};

return [{
  case_id: c.id ?? webhookBody.case_id ?? null,
  user_message,
}];

const coerceToString = (v) => {
  if (v == null) return "";
  if (typeof v === "string") return v;
  if (typeof v === "object") {
    if (typeof v.text === "string") return v.text;
    if (typeof v.output === "string") return v.output;
    if (typeof v.response === "string") return v.response;
    if (v.response && typeof v.response.text === "string") return v.response.text;
  }
  return String(v);
};

const caseData = $items("Fetch Case (Plan)")[0]?.json ?? {};
const buildPromptData = $items("Build Plan Prompt")[0]?.json ?? {};
const webhookBody = $node["Webhook - Plan"]?.json?.body ?? {};

const triageData = caseData.triage_decision ?? {};
const fallbackResolutionType =
  triageData.resolution_type ??
  caseData.resolution_preference ??
  buildPromptData?.user_message?.resolution_type ??
  null;

const txnAmount =
  caseData?.triage_data?.eligible_amount ??
  caseData?.information_bundle?.transaction?.amount ??
  caseData?.information_bundle?.order_data?.total_amount ??
  caseData?.information_bundle?.order?.total_amount ??
  null;

let plan;
try {
  if ($json && typeof $json === "object" && $json.resolution_type) {
    plan = $json;
  } else {
    const text = coerceToString($json);
    plan = JSON.parse(text);
  }
} catch (e) {
  plan = null;
}

const validTypes = ["refund", "replacement", "return"];

if (!plan || !validTypes.includes(String(plan.resolution_type || "").trim().toLowerCase())) {
  const normalizedFallback = String(fallbackResolutionType || "refund").trim().toLowerCase();

  plan = {
    resolution_type: validTypes.includes(normalizedFallback) ? normalizedFallback : "refund",
    amount: normalizedFallback === "refund" ? txnAmount : null,
    steps: ["Review case and proceed with the approved resolution workflow."],
    customer_message:
      normalizedFallback === "replacement"
        ? "Your replacement request is being prepared."
        : normalizedFallback === "return"
          ? "Your return request is being prepared and next steps will follow shortly."
          : "Your refund is being prepared.",
  };
}

plan.resolution_type = String(plan.resolution_type || "").trim().toLowerCase();

if (!validTypes.includes(plan.resolution_type)) {
  plan.resolution_type = validTypes.includes(String(fallbackResolutionType || "").trim().toLowerCase())
    ? String(fallbackResolutionType).trim().toLowerCase()
    : "refund";
}

if (!Array.isArray(plan.steps)) {
  plan.steps = ["Review case and proceed with the approved resolution workflow."];
} else {
  plan.steps = plan.steps
    .map((s) => String(s ?? "").trim())
    .filter(Boolean);

  if (plan.steps.length === 0) {
    plan.steps = ["Review case and proceed with the approved resolution workflow."];
  }
}

if (plan.resolution_type === "refund") {
  const amountNum = Number(plan.amount);
  if (!Number.isFinite(amountNum)) {
    const txnNum = Number(txnAmount);
    plan.amount = Number.isFinite(txnNum) ? txnNum : null;
  } else {
    plan.amount = amountNum;
  }
} else {
  plan.amount = null;
}

if (typeof plan.customer_message !== "string" || !plan.customer_message.trim()) {
  plan.customer_message =
    plan.resolution_type === "replacement"
      ? "Your replacement request is being prepared."
      : plan.resolution_type === "return"
        ? "Your return request is being prepared and next steps will follow shortly."
        : "Your refund is being prepared.";
}

return [{
  case_id: buildPromptData.case_id || webhookBody.case_id || caseData.id || null,
  ...plan,
}];

const c = $items("Fetch Case + Plan")[0]?.json ?? {};
const webhookBody = $node["Webhook - Approved"]?.json?.body ?? {};

const triageDecision = c.triage_decision ?? {};
const resolutionPlan = c.resolution_plan ?? {};

const resolutionType =
  triageDecision.resolution_type ??
  resolutionPlan.resolution_type ??
  c.resolution_preference ??
  null;

const user_message = {
  case: {
    id: c.id ?? webhookBody.case_id ?? null,
    order_id: c.order_id ?? null,
    status: c.status ?? null,
    dispute_type: c.dispute_type ?? null,
    dispute_subtype: c.dispute_subtype ?? null,
    resolution_preference: c.resolution_preference ?? null,
  },
  resolution_type: resolutionType,
  triage_decision: triageDecision,
  resolution_plan: resolutionPlan,
  information_bundle: c.information_bundle ?? null,
};

return {
  case_id: c.id ?? webhookBody.case_id ?? null,
  user_message,
};

